"""
Regression test for GitHub issue #12446:
pytest 8.2.0 calls @property during unittest collection.

The bug: during fixture discovery, pytest would call `safe_getattr(holderobj, name, None)`
on the instance, which would trigger @property descriptors to execute.

The fix: first check the type (class) for the fixture marker without triggering
descriptors, and only access the instance attribute if it's actually a fixture.
"""
from __future__ import annotations

from _pytest.config import ExitCode
from _pytest.pytester import Pytester
import pytest


class TestPropertyNotCalledDuringCollection:
    def test_property_not_called_during_collection(self, pytester: Pytester) -> None:
        """Regression test for #12446: @property should not be called during collection."""
        pytester.makepyfile(
            """\
            class TestCase:
                @property
                def oops(self):
                    raise SystemExit('do not call me during collection!')
            """
        )
        result = pytester.runpytest()
        assert result.ret == ExitCode.NO_TESTS_COLLECTED

    def test_property_not_called_during_collection_with_unittest(
        self, pytester: Pytester
    ) -> None:
        """Regression test for #12446: @property in unittest.TestCase subclass should not be called."""
        pytester.makepyfile(
            """\
            import unittest

            class BaseTest(unittest.TestCase):
                @property
                def variable(self):
                    raise SystemExit('property was called during collection!')

            class MyTest(BaseTest):
                def test_simple(self):
                    assert True
            """
        )
        result = pytester.runpytest()
        # Should collect and pass test_simple without calling the property
        assert result.ret == ExitCode.OK
        result.assert_outcomes(passed=1)

    def test_instance_descriptor_not_called_during_collection(
        self, pytester: Pytester
    ) -> None:
        """Regression test for #12446: custom instance descriptors should not be called during collection."""
        pytester.makepyfile(
            """\
            class MyProperty:
                def __init__(self, func):
                    self._func = func
                def __get__(self, inst, owner):
                    if inst is None:
                        return self
                    else:
                        return self._func.__get__(inst, owner)()

            class TestCase:
                @MyProperty
                def oops(self):
                    raise SystemExit('descriptor was called during collection!')
            """
        )
        result = pytester.runpytest()
        assert result.ret == ExitCode.NO_TESTS_COLLECTED

    def test_property_with_side_effects_not_triggered(
        self, pytester: Pytester
    ) -> None:
        """Regression test for #12446: properties with side effects should not be triggered."""
        pytester.makepyfile(
            """\
            import unittest

            _call_count = []

            class BaseTest(unittest.TestCase):
                @property
                def slow_property(self):
                    _call_count.append(1)
                    return 'value'

            class MyTest(BaseTest):
                def test_simple(self):
                    # The property should NOT have been called during collection
                    assert True
            """
        )
        result = pytester.runpytest()
        assert result.ret == ExitCode.OK
        result.assert_outcomes(passed=1)

    def test_property_raising_system_exit_does_not_abort_collection(
        self, pytester: Pytester
    ) -> None:
        """Regression test for #12446: a property raising SystemExit should not abort pytest collection."""
        pytester.makepyfile(
            """\
            import unittest

            class BaseTest(unittest.TestCase):
                @property
                def bad_property(self):
                    raise SystemExit(1)

            class MyTest(BaseTest):
                def test_something(self):
                    assert True
            """
        )
        result = pytester.runpytest()
        # With the bug, SystemExit from the property would abort pytest
        # With the fix, the property is never called, so collection succeeds
        assert result.ret == ExitCode.OK
        result.assert_outcomes(passed=1)

